SELECT preferences.*, pharmacies.pharmacy_name
FROM patient_pharmacy_preferences AS preferences
JOIN pharmacies ON preferences.pharmacy_id = pharmacies.pharmacy_id;

SELECT SUM(pi.quantity_on_hand * pr.unit_price) AS total_price 
FROM pharmacy_inventory pi 
JOIN products pr ON pi.product_id = pr.product_id;

SELECT COUNT(*) AS product_count
FROM pharmacy_inventory
WHERE quantity_on_hand > reorder_threshold;

SELECT review_id, prescription_id, patient_id, rating, comment, review_date, reviewer_name 
FROM prescription_reviews 
WHERE prescription_id = 1;

SELECT pharmacy_id, COUNT(*) AS number_of_staff_members
FROM pharmacy_staff
GROUP BY pharmacy_id;

SELECT SUM(pr.quantity) AS total_quantity
FROM prescriptions pr
WHERE pr.pickup_date IS NOT NULL;
